#!/usr/bin/env node
/**
 * Wave 11 Analysis Deepening Tests
 *
 * Covers:
 * 1. Architecture boundary validation (configured + autogenerated, cyclic exclusion, test exclusion, flat dir)
 * 2. Flat dispatcher / code smell detection across JS/TS, Python, Java
 * 3. Complexity trend calculation (AST parity fallback, untracked files)
 * 4. Unified 5-dimension risk scoring breakdown
 */

const assert = require('assert');
const fs = require('fs');
const os = require('os');
const path = require('path');
const { parsePython } = require('../src/services/dep-graph/parsers/python');
const { parseJava } = require('../src/services/dep-graph/parsers/java');
const { parseCppAst } = require('../src/services/dep-graph/parsers/cpp-ast');
const { runGit } = require('../src/utils/command');

const { checkBoundaries } = require('../src/tools/dep-tools/boundaries');
const { checkSmells } = require('../src/tools/dep-tools/smells');
const { getFileComplexityTrend } = require('../src/tools/complexity-tools');
const { buildCompositeRisk } = require('../src/cli/formatters/composite-risk');
const { buildFunctionFingerprint } = require('../src/services/dep-graph/parsers/shared');
const { makeTempDir, cleanupTempDir } = require('./test-helpers');

const REPO_ROOT = path.join(__dirname, '..');

/* -------------------------------------------------------------------------- */
// 1. Architecture Boundaries
/* -------------------------------------------------------------------------- */

function createMockGraph(filePaths, dependencyMap) {
  return {
    getAllFilePaths: () => filePaths,
    getDependencies: (file) => dependencyMap.get(file) || [],
  };
}

function createMockProjectContext(classifications, boundaries = []) {
  return {
    classifyFile: (filePath) => classifications.get(filePath) || { isMainline: true },
    config: { boundaries },
  };
}

function testConfiguredBoundaries() {
  const root = '/project';
  const files = [
    path.join(root, 'src', 'cli', 'cmd.js'),
    path.join(root, 'src', 'services', 'core.js'),
    path.join(root, 'src', 'utils', 'help.js'),
  ];
  const deps = new Map([
    [files[0], [files[1]]], // cli/cmd.js -> services/core.js (violation: cli is denied from importing services)
    [files[2], [files[1]]], // utils/help.js -> services/core.js (not a violation since utils is not denied)
  ]);
  const graph = createMockGraph(files, deps);
  const ctx = createMockProjectContext(new Map(), [
    { from: 'src/cli/**', deny: ['src/services/**'] }
  ]);

  const result = checkBoundaries({ cwd: root }, { snapshot: { graph }, projectContext: ctx, workspaceRoot: root });
  assert.strictEqual(result.ok, true);
  assert.strictEqual(result.violationsCount, 1);
  assert.strictEqual(result.violations[0].sourceFile, 'src/cli/cmd.js');
  assert.strictEqual(result.violations[0].targetFile, 'src/services/core.js');
  assert.strictEqual(result.violations[0].violationType, 'deny');
}

function testAutogenerateBoundaries() {
  const root = '/project';
  const files = [
    path.join(root, 'src', 'cli', 'cmd.js'),
    path.join(root, 'src', 'services', 'core.js'),
  ];
  const deps = new Map([
    [files[0], [files[1]]], // cli imports services
  ]);
  const graph = createMockGraph(files, deps);
  const classifications = new Map([
    [files[0], { isMainline: true }],
    [files[1], { isMainline: true }],
  ]);
  const ctx = createMockProjectContext(classifications, []);

  const result = checkBoundaries({ cwd: root }, { snapshot: { graph }, projectContext: ctx, workspaceRoot: root });
  assert.strictEqual(result.ok, true);
  assert.strictEqual(result.isAutogenerated, true);
  assert(result.rulesApplied.length > 0, 'Should suggest at least one rule');
  // services is lower-level than cli, so services should deny cli
  const rule = result.rulesApplied.find(r => r.from === 'src/services/**');
  assert(rule, `Should have a rule from src/services/**, got: ${JSON.stringify(result.rulesApplied)}`);
  assert(rule.deny.includes('src/cli/**'), `Rule should deny cli: ${JSON.stringify(rule)}`);
}

function testCyclicExclusion() {
  const root = '/project';
  const files = [
    path.join(root, 'src', 'a', 'a.js'),
    path.join(root, 'src', 'b', 'b.js'),
  ];
  const deps = new Map([
    [files[0], [files[1]]],
    [files[1], [files[0]]],
  ]);
  const graph = createMockGraph(files, deps);
  const classifications = new Map([
    [files[0], { isMainline: true }],
    [files[1], { isMainline: true }],
  ]);
  const ctx = createMockProjectContext(classifications, []);

  const result = checkBoundaries({ cwd: root }, { snapshot: { graph }, projectContext: ctx, workspaceRoot: root });
  assert.strictEqual(result.ok, true);
  assert.strictEqual(result.isAutogenerated, true);
  // Cyclic dependency: A imports B and B imports A -> no rule should be suggested
  const rulesAB = result.rulesApplied.filter(r =>
    (r.from === 'src/a/**' && r.deny?.includes('src/b/**')) ||
    (r.from === 'src/b/**' && r.deny?.includes('src/a/**'))
  );
  assert.strictEqual(rulesAB.length, 0, 'Cyclic dependencies should not generate rules');
}

function testFlatDirectoryBypass() {
  const root = '/project';
  // All files in the same directory -> only 1 unique 2-level prefix -> no rules
  const files = [
    path.join(root, 'src', 'a.js'),
    path.join(root, 'src', 'b.js'),
  ];
  const deps = new Map([
    [files[0], [files[1]]],
  ]);
  const graph = createMockGraph(files, deps);
  const classifications = new Map([
    [files[0], { isMainline: true }],
    [files[1], { isMainline: true }],
  ]);
  const ctx = createMockProjectContext(classifications, []);

  const result = checkBoundaries({ cwd: root }, { snapshot: { graph }, projectContext: ctx, workspaceRoot: root });
  assert.strictEqual(result.ok, true);
  assert.strictEqual(result.rulesApplied.length, 0, 'Flat workspace (single directory) should return empty rules');
}

function testNonMainlineExclusion() {
  const root = '/project';
  const files = [
    path.join(root, 'src', 'services', 'core.js'),
    path.join(root, 'test', 'core-test.js'),
  ];
  const deps = new Map([
    [files[1], [files[0]]], // test imports mainline
  ]);
  const graph = createMockGraph(files, deps);
  const classifications = new Map([
    [files[0], { isMainline: true }],
    [files[1], { isMainline: false }],
  ]);
  const ctx = createMockProjectContext(classifications, []);

  const result = checkBoundaries({ cwd: root }, { snapshot: { graph }, projectContext: ctx, workspaceRoot: root });
  assert.strictEqual(result.ok, true);
  // Test file should be excluded from both source and target of violations
  const violationsInvolvingTest = result.violations.filter(v =>
    v.sourceFile.includes('test') || v.targetFile.includes('test')
  );
  assert.strictEqual(violationsInvolvingTest.length, 0, 'Test files should be excluded');
}

/* -------------------------------------------------------------------------- */
// 2. Flat Dispatcher / Code Smell Detection
/* -------------------------------------------------------------------------- */

function testJsIfElseArmsCount() {
  // Simulate: if (a) {} else if (b) {} else if (c) {} else {}
  const functionNode = {
    type: 'FunctionDeclaration',
    params: [],
    async: false,
    generator: false,
    body: {
      type: 'BlockStatement',
      body: [
        {
          type: 'IfStatement',
          test: { type: 'Identifier', name: 'a' },
          consequent: { type: 'BlockStatement', body: [] },
          alternate: {
            type: 'IfStatement',
            test: { type: 'Identifier', name: 'b' },
            consequent: { type: 'BlockStatement', body: [] },
            alternate: {
              type: 'IfStatement',
              test: { type: 'Identifier', name: 'c' },
              consequent: { type: 'BlockStatement', body: [] },
              alternate: { type: 'BlockStatement', body: [] },
            },
          },
        },
      ],
    },
  };

  const fp = buildFunctionFingerprint(functionNode);
  assert.strictEqual(fp.maxArms, 4, `Expected 4 arms for if/else-if/else-if/else, got ${fp.maxArms}`);
}

function testJsSwitchArmsCount() {
  const functionNode = {
    type: 'FunctionDeclaration',
    params: [],
    async: false,
    generator: false,
    body: {
      type: 'BlockStatement',
      body: [
        {
          type: 'SwitchStatement',
          discriminant: { type: 'Identifier', name: 'x' },
          cases: [
            { type: 'SwitchCase', test: { type: 'Literal', value: 1 } },
            { type: 'SwitchCase', test: { type: 'Literal', value: 2 } },
            { type: 'SwitchCase', test: { type: 'Literal', value: 3 } },
          ],
        },
      ],
    },
  };

  const fp = buildFunctionFingerprint(functionNode);
  assert.strictEqual(fp.maxArms, 3, `Expected 3 switch arms, got ${fp.maxArms}`);
}

function testJsFlatDispatcherDetection() {
  // Path 1: arms >= 6 and cc <= arms + 5
  // Create a function with 6 if-else arms and low branch count
  const body = [];
  let current = null;
  for (let i = 0; i < 6; i++) {
    const ifStmt = {
      type: 'IfStatement',
      test: { type: 'Identifier', name: `c${i}` },
      consequent: { type: 'BlockStatement', body: [] },
      alternate: null,
    };
    if (i === 0) {
      current = ifStmt;
      body.push(ifStmt);
    } else {
      let tail = current;
      while (tail.alternate && tail.alternate.type === 'IfStatement') {
        tail = tail.alternate;
      }
      tail.alternate = ifStmt;
    }
  }

  const functionNode = {
    type: 'FunctionDeclaration',
    params: [],
    async: false,
    generator: false,
    body: { type: 'BlockStatement', body },
  };

  const fp = buildFunctionFingerprint(functionNode);
  assert(fp.maxArms >= 6, `Expected at least 6 arms for flat dispatcher, got ${fp.maxArms}`);

  // Now test via checkSmells
  const mockGraph = {
    getAllFilePaths: () => ['/project/src/dispatcher.js'],
    getFileInfo: () => ({
      functionRecords: [
        { name: 'dispatch', lineStart: 1, lineEnd: 50, fingerprint: fp },
      ],
    }),
  };
  const result = checkSmells({}, { snapshot: { graph: mockGraph }, workspaceRoot: '/project' });
  assert.strictEqual(result.ok, true);
  assert(result.smellsCount > 0, 'Should detect flat dispatcher smell');
  const smell = result.smells.find(s => s.functionName === 'dispatch');
  assert(smell, 'Should report dispatch function as smell');
}

async function testPythonElifChain() {
  const source = `
def dispatch(x):
    if x == 1:
        return "one"
    elif x == 2:
        return "two"
    elif x == 3:
        return "three"
    elif x == 4:
        return "four"
    else:
        return "other"
`;
  const parsed = await parsePython(source, 'test.py');
  if (!parsed) {
    console.log('Python parser skipped (not available)');
    return;
  }
  assert(Array.isArray(parsed.functionRecords), 'Should have functionRecords');
  const dispatchFn = parsed.functionRecords.find(f => f.name === 'dispatch');
  assert(dispatchFn, 'Should find dispatch function');
  assert(dispatchFn.fingerprint, 'Should have fingerprint');
  assert.strictEqual(dispatchFn.fingerprint.maxArms, 5, `Expected 5 arms (if + 3 elif + else), got ${dispatchFn.fingerprint.maxArms}`);
  assert.strictEqual(dispatchFn.branchCount, dispatchFn.fingerprint.branchCount, 'branchCount should be lifted to functionRecord top level');
  assert.strictEqual(dispatchFn.maxArms, dispatchFn.fingerprint.maxArms, 'maxArms should be lifted to functionRecord top level');
}

async function testJavaElseIfChain() {
  const source = `
public class Dispatcher {
    public String dispatch(int x) {
        if (x == 1) {
            return "one";
        } else if (x == 2) {
            return "two";
        } else if (x == 3) {
            return "three";
        } else if (x == 4) {
            return "four";
        } else {
            return "other";
        }
    }
}
`;
  const parsed = await parseJava(source, 'Dispatcher.java');
  if (!parsed) {
    console.log('Java parser skipped (javalang not available)');
    return;
  }
  assert(Array.isArray(parsed.functionRecords), 'Should have functionRecords');
  const dispatchFn = parsed.functionRecords.find(f => f.name === 'dispatch');
  assert(dispatchFn, 'Should find dispatch function');
  assert(dispatchFn.fingerprint, 'Should have fingerprint');
  assert.strictEqual(dispatchFn.fingerprint.maxArms, 5, `Expected 5 arms (if + 3 else-if + else), got ${dispatchFn.fingerprint.maxArms}`);
}

async function testCppFlatDispatcherDetection() {
  const source = `
int dispatch(int x) {
  if (x == 1) return 1;
  else if (x == 2) return 2;
  else if (x == 3) return 3;
  else if (x == 4) return 4;
  else if (x == 5) return 5;
  else if (x == 6) return 6;
  return 0;
}
`;
  const parsed = await parseCppAst(source, 'Dispatcher.c');
  if (!parsed) {
    console.log('C/C++ parser skipped (tree-sitter not available)');
    return;
  }
  assert(Array.isArray(parsed.functionRecords), 'Should have functionRecords');
  const dispatchFn = parsed.functionRecords.find(f => f.name === 'dispatch');
  assert(dispatchFn, 'Should find dispatch function');
  assert.strictEqual(dispatchFn.maxArms, 6, `Expected 6 arms for C flat dispatcher, got ${dispatchFn.maxArms}`);

  const mockGraph = {
    getAllFilePaths: () => ['/project/src/dispatch.c'],
    getFileInfo: () => ({ functionRecords: parsed.functionRecords }),
  };
  const result = checkSmells({}, { snapshot: { graph: mockGraph }, workspaceRoot: '/project' });
  assert.strictEqual(result.ok, true);
  assert(result.smellsCount > 0, 'Should detect flat dispatcher smell in C/C++');
  const smell = result.smells.find(s => s.functionName === 'dispatch');
  assert(smell, 'Should report C/C++ dispatch function as smell');
}

/* -------------------------------------------------------------------------- */
// 3. Complexity Trend
/* -------------------------------------------------------------------------- */

async function testComplexityTrendStable() {
  // Use a stable file from the repo itself
  const filePath = path.join(REPO_ROOT, 'src', 'config', 'constants.js');
  const trend = await getFileComplexityTrend(REPO_ROOT, filePath, { commits: 'HEAD~3..HEAD' });
  assert(['GROWING', 'SHRINKING', 'STABLE'].includes(trend), `Expected valid trend, got ${trend}`);
}

async function testComplexityTrendUntracked() {
  const tmpDir = makeTempDir('wb-test-trend-');
  // Initialize a git repo
  await runGit(['init'], tmpDir);
  await runGit(['config', 'user.email', 'test@test.com'], tmpDir);
  await runGit(['config', 'user.name', 'Test'], tmpDir);

  const filePath = path.join(tmpDir, 'newfile.js');
  fs.writeFileSync(filePath, 'function foo() { return 1; }\n', 'utf8');

  // File is untracked (not committed), so git show should fail
  const trend = await getFileComplexityTrend(tmpDir, filePath, {});
  cleanupTempDir(tmpDir);
  assert.strictEqual(trend, 'GROWING', 'Untracked file should trend GROWING');
}

async function testComplexityTrendFallbackToLoc() {
  // Use a non-parseable file (e.g., a markdown file) to force LOC fallback
  const tmpDir = makeTempDir('wb-test-trend-md-');
  await runGit(['init'], tmpDir);
  await runGit(['config', 'user.email', 'test@test.com'], tmpDir);
  await runGit(['config', 'user.name', 'Test'], tmpDir);

  const filePath = path.join(tmpDir, 'README.md');
  fs.writeFileSync(filePath, '# Title\n\nLine 2\nLine 3\nLine 4\n', 'utf8');
  await runGit(['add', '.'], tmpDir);
  await runGit(['commit', '-m', 'initial'], tmpDir);

  // Add more lines
  fs.writeFileSync(filePath, '# Title\n\nLine 2\nLine 3\nLine 4\nLine 5\nLine 6\nLine 7\nLine 8\nLine 9\nLine 10\nLine 11\nLine 12\n', 'utf8');

  const trend = await getFileComplexityTrend(tmpDir, filePath, {});
  cleanupTempDir(tmpDir);
  assert.strictEqual(trend, 'GROWING', 'LOC fallback should detect growth when lines increase by >10%');
}

/* -------------------------------------------------------------------------- */
// 4. Unified 5-Dimension Risk Scoring
/* -------------------------------------------------------------------------- */

function testRiskDimensionsStructure() {
  const entry = {
    file: 'src/auth/login.js',
    impactCount: 8,
    affectedTestsCount: 0,
    affectedRoutes: [{ path: '/login' }, { path: '/logout' }],
    impact: [
      { file: 'src/services/user.js' },
      { file: 'src/cli/cmd.js' },
      { file: 'src/utils/hash.js' },
    ],
    frameworkPattern: 'express-route',
    classification: { isMainline: true, isEntry: false },
  };

  const risk = buildCompositeRisk(entry);
  assert.strictEqual(typeof risk.score, 'number');
  assert.strictEqual(typeof risk.level, 'string');
  assert(Array.isArray(risk.reasons));
  assert(risk.dimensions, 'Should have dimensions breakdown');
  assert.strictEqual(typeof risk.dimensions.flow_participation, 'number');
  assert.strictEqual(typeof risk.dimensions.community_crossing, 'number');
  assert.strictEqual(typeof risk.dimensions.test_coverage, 'number');
  assert.strictEqual(typeof risk.dimensions.caller_count, 'number');
  assert.strictEqual(typeof risk.dimensions.security_sensitive, 'number');
}

function testRiskSecuritySensitive() {
  const entry = {
    file: 'src/auth/token-manager.js',
    impactCount: 2,
    affectedTestsCount: 1,
    affectedRoutes: [],
    impact: [{ file: 'src/app.js' }],
    classification: { isMainline: true },
  };

  const risk = buildCompositeRisk(entry);
  assert.strictEqual(risk.dimensions.security_sensitive, 2, 'Security sensitive file should score 2');
  assert(risk.reasons.some(r => r.includes('Security sensitive')), 'Should mention security in reasons');
}

function testRiskMainlineDowngrade() {
  const entry = {
    file: 'test/helper.js',
    impactCount: 5,
    affectedTestsCount: 0,
    affectedRoutes: [],
    impact: [{ file: 'src/a.js' }, { file: 'src/b.js' }],
    classification: { isMainline: false },
  };

  const baseRisk = buildCompositeRisk({ ...entry, classification: { isMainline: true } });
  const downgradedRisk = buildCompositeRisk(entry);

  assert(downgradedRisk.score <= baseRisk.score, 'Non-mainline file should have downgraded score');
}

function testRiskCommunityCrossing() {
  const entry = {
    file: 'src/core/engine.js',
    impactCount: 5,
    affectedTestsCount: 0,
    affectedRoutes: [],
    impact: [
      { file: 'src/cli/format.js' },
      { file: 'src/services/db.js' },
      { file: 'src/utils/path.js' },
    ],
    classification: { isMainline: true },
  };

  const risk = buildCompositeRisk(entry);
  assert.strictEqual(risk.dimensions.community_crossing, 3, '3 unique 2-level prefixes should score 3');
}

function testRiskTestCoverageGap() {
  const entry = {
    file: 'src/core/engine.js',
    impactCount: 5,
    affectedTestsCount: 0,
    affectedRoutes: [],
    impact: [{ file: 'src/a.js' }],
    classification: { isMainline: true },
  };

  const risk = buildCompositeRisk(entry);
  assert.strictEqual(risk.dimensions.test_coverage, 3, '0 tests + impact >= 3 should score 3');
  assert(risk.reasons.some(r => r.includes('test coverage gap')), 'Should mention coverage gap');
}

/* -------------------------------------------------------------------------- */
// Runner
/* -------------------------------------------------------------------------- */

async function main() {
  const tests = [
    testConfiguredBoundaries,
    testAutogenerateBoundaries,
    testCyclicExclusion,
    testFlatDirectoryBypass,
    testNonMainlineExclusion,
    testJsIfElseArmsCount,
    testJsSwitchArmsCount,
    testJsFlatDispatcherDetection,
    testRiskDimensionsStructure,
    testRiskSecuritySensitive,
    testRiskMainlineDowngrade,
    testRiskCommunityCrossing,
    testRiskTestCoverageGap,
  ];

  const asyncTests = [
    testPythonElifChain,
    testJavaElseIfChain,
    testCppFlatDispatcherDetection,
    testComplexityTrendStable,
    testComplexityTrendUntracked,
    testComplexityTrendFallbackToLoc,
  ];

  let passed = 0;
  let failed = 0;

  for (const test of tests) {
    try {
      test();
      passed++;
    } catch (err) {
      failed++;
      console.error(`FAIL: ${test.name}\n  ${err.message}`);
    }
  }

  for (const test of asyncTests) {
    try {
      await test();
      passed++;
    } catch (err) {
      failed++;
      console.error(`FAIL: ${test.name}\n  ${err.message}`);
    }
  }

  console.log(`\nWave 11 tests: ${passed} passed, ${failed} failed`);
  if (failed > 0) process.exit(1);
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});
